var findPermutationDifference = function(s, t) {
    const pos = {};
    for (let i = 0; i < s.length; i++) pos[s[i]] = i;
    let total = 0;
    for (let j = 0; j < t.length; j++) total += Math.abs(pos[t[j]] - j);
    return total;
};
